# Scratch: "ከሆነ ታዲያ" ብሎክ ጋር ተመሳሳይ
yeayer_hunieta = input("የአየር ሁኔታ እንዴት ነው? (ፀሐያማ/ዝናባማ): ")
if yeayer_hunieta == "ፀሐያማ":
    print("ውጭ እንጫወት!")
else:
    print("ፕሮግራሚንግ እንስራ!")

# Scratch: "ከሆነ ታዲያ አለበለዚያ ከሆነ ታዲያ" ብሎክ ጋር ተመሳሳይ
seat = int(input("አሁን ስንት ሰዓት ነው? (0-23): "))
if seat < 10:
    print("እንደምን አደርክ!")
elif seat < 17:
    print("እንደምን ዋልክ!")
else:
    print("እንደምን አመሸህ!")

